// Store for authorization codes: code -> { client_id, redirect_uri, user, expires_at, scope, code_challenge, code_challenge_method }
const authorizationCodes = new Map();

// Store for access tokens: token -> { client_id, user, expires_at, scope }
const accessTokens = new Map();

// Store for refresh tokens: token -> { client_id, user, scope }
const refreshTokens = new Map();

// Utility functions
function generateCode() {
  return crypto.randomBytes(32).toString('hex');
}

function generateToken() {
  return crypto.randomBytes(64).toString('hex');
}

function validateClient(client_id, redirect_uri) {
  const client = registeredClients[client_id];
  if (!client) return null;
  if (redirect_uri && !client.redirect_uris.includes(redirect_uri)) return null;
  return client;
}

function cleanupExpiredEntries() {
  const now = Date.now();
  for (const [code, data] of authorizationCodes) {
    if (data.expires_at < now) authorizationCodes.delete(code);
  }
  for (const [token, data] of accessTokens) {
    if (data.expires_at < now) accessTokens.delete(token);
  }
}

setInterval(cleanupExpiredEntries, 60000);

// PKCE support
function generateCodeChallenge(codeVerifier, method) {
  if (method === 'S256') {
    return crypto.createHash('sha256').update(codeVerifier).digest('base64url');
  }
  return codeVerifier; // plain method
}

// Middleware to authenticate bearer tokens
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid Authorization header' });
  }
  const token = authHeader.split(' ')[1];
  const tokenData = accessTokens.get(token);
  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token not found or expired' });
  }
  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token has expired' });
  }
  req.tokenData = tokenData;
  req.accessToken = token;
  next();
}

