// GET /authorize?response_type=code&client_id=...&redirect_uri=...&state=...&scope=...
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, state, scope, code_challenge, code_challenge_method } = req.query;

  // Validate response_type
  if (response_type !== 'code') {
    return res.status(400).send(renderError('Unsupported response_type. Only "code" is supported.'));
  }

  // Validate client
  const client = validateClient(client_id, redirect_uri);
  if (!client) {
    return res.status(400).send(renderError('Invalid client_id or redirect_uri.'));
  }

  // If user is already logged in via SSO session, skip login form
  if (req.session && req.session.user) {
    const code = generateCode();
    authorizationCodes.set(code, {
      client_id,
      redirect_uri,
      user: req.session.user,
      expires_at: Date.now() + 600000, // 10 minutes
      scope: scope || 'openid profile email',
      code_challenge: code_challenge || null,
      code_challenge_method: code_challenge_method || null
    });

    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.set('code', code);
    if (state) redirectUrl.searchParams.set('state', state);
    return res.redirect(redirectUrl.toString());
  }

  // Store authorization request in session
  req.session.authRequest = { client_id, redirect_uri, state, scope, code_challenge, code_challenge_method };

  // Render login page
  res.send(renderLoginPage(client.name, state));
});

// POST /authorize - handle login form submission
app.post('/authorize', (req, res) => {
  const { username, password } = req.body;
  const authRequest = req.session.authRequest;

  if (!authRequest) {
    return res.status(400).send(renderError('No pending authorization request. Please start the flow again.'));
  }

  const { client_id, redirect_uri, state, scope, code_challenge, code_challenge_method } = authRequest;

  // Validate client again
  const client = validateClient(client_id, redirect_uri);
  if (!client) {
    return res.status(400).send(renderError('Invalid client configuration.'));
  }

  // Authenticate user
  const user = users[username];
  if (!user || user.password !== password) {
    return res.send(renderLoginPage(client.name, state, 'Invalid username or password.'));
  }

  // Create SSO session
  req.session.user = {
    username: user.username,
    email: user.email,
    role: user.role,
    name: user.name
  };

  // Generate authorization code
  const code = generateCode();
  authorizationCodes.set(code, {
    client_id,
    redirect_uri,
    user: req.session.user,
    expires_at: Date.now() + 600000,
    scope: scope || 'openid profile email',
    code_challenge: code_challenge || null,
    code_challenge_method: code_challenge_method || null
  });

  // Clean up auth request from session
  delete req.session.authRequest;

  // Redirect back to client with authorization code
  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.set('code', code);
  if (state) redirectUrl.searchParams.set('state', state);
  res.redirect(redirectUrl.toString());
});

