app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code and refresh_token grant types are supported'
    });
  }
});

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri, client_id, client_secret, code_verifier } = req.body;

  // Authenticate client (support both body and basic auth)
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.split(' ')[1], 'base64').toString();
    const [id, secret] = decoded.split(':');
    authenticatedClientId = decodeURIComponent(id);
    authenticatedClientSecret = decodeURIComponent(secret);
  }

  if (!authenticatedClientId) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  const client = registeredClients[authenticatedClientId];
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Unknown client' });
  }

  // PKCE flow doesn't require client_secret, but standard flow does
  const codeData = authorizationCodes.get(code);
  if (codeData && codeData.code_challenge) {
    // PKCE flow - verify code_verifier
    if (!code_verifier) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'code_verifier is required for PKCE' });
    }
  } else {
    // Standard flow - require client_secret
    if (client.client_secret !== authenticatedClientSecret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
  }

  // Validate authorization code
  if (!code || !codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired authorization code' });
  }

  // Check expiration
  if (codeData.expires_at < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired' });
  }

  // Verify client_id matches
  if (codeData.client_id !== authenticatedClientId) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  // Verify redirect_uri matches
  if (redirect_uri && codeData.redirect_uri !== redirect_uri) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  // Verify PKCE code_verifier if applicable
  if (codeData.code_challenge) {
    const method = codeData.code_challenge_method || 'plain';
    const expectedChallenge = generateCodeChallenge(code_verifier, method);
    if (expectedChallenge !== codeData.code_challenge) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid code_verifier' });
    }
  }

  // Consume the authorization code (one-time use)
  authorizationCodes.delete(code);

  // Generate tokens
  const accessToken = generateToken();
  const refreshToken = generateToken();
  const expiresIn = 3600; // 1 hour

  accessTokens.set(accessToken, {
    client_id: authenticatedClientId,
    user: codeData.user,
    expires_at: Date.now() + (expiresIn * 1000),
    scope: codeData.scope
  });

  refreshTokens.set(refreshToken, {
    client_id: authenticatedClientId,
    user: codeData.user,
    scope: codeData.scope
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token, client_id, client_secret, scope } = req.body;

  // Authenticate client
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.split(' ')[1], 'base64').toString();
    const [id, secret] = decoded.split(':');
    authenticatedClientId = decodeURIComponent(id);
    authenticatedClientSecret = decodeURIComponent(secret);
  }

  if (!authenticatedClientId) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  const client = registeredClients[authenticatedClientId];
  if (!client || client.client_secret !== authenticatedClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  // Validate refresh token
  const tokenData = refreshTokens.get(refresh_token);
  if (!tokenData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
  }

  if (tokenData.client_id !== authenticatedClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token was not issued to this client' });
  }

  // Check if requested scope is subset of original scope
  const originalScopes = (tokenData.scope || '').split(' ');
  const requestedScopes = scope ? scope.split(' ') : originalScopes;
  const isSubset = requestedScopes.every(s => originalScopes.includes(s));
  if (!isSubset) {
    return res.status(400).json({ error: 'invalid_scope', error_description: 'Requested scope exceeds original grant' });
  }

  // Rotate refresh token
  refreshTokens.delete(refresh_token);

  // Generate new tokens
  const newAccessToken = generateToken();
  const newRefreshToken = generateToken();
  const expiresIn = 3600;

  // Re-fetch user info (in case it was updated)
  const currentUser = users[tokenData.user.username];
  const userInfo = currentUser ? {
    username: currentUser.username,
    email: currentUser.email,
    role: currentUser.role,
    name: currentUser.name
  } : tokenData.user;

  accessTokens.set(newAccessToken, {
    client_id: authenticatedClientId,
    user: userInfo,
    expires_at: Date.now() + (expiresIn * 1000),
    scope: requestedScopes.join(' ')
  });

  refreshTokens.set(newRefreshToken, {
    client_id: authenticatedClientId,
    user: userInfo,
    scope: requestedScopes.join(' ')
  });

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: requestedScopes.join(' ')
  });
}

// ========================
// Token Introspection Endpoint (RFC 7662)
// ========================
app.post('/introspect', (req, res) => {
  const { token, token_type_hint } = req.body;

  // Authenticate the calling client
  const authHeader = req.headers['authorization'];
  let clientId, clientSecret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.split(' ')[1], 'base64').toString();
    [clientId, clientSecret] = decoded.split(':').map(decodeURIComponent);
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = registeredClients[clientId];
  if (!client || client.client_secret !== clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  // Check access tokens
  const tokenData = accessTokens.get(token);
  if (tokenData && tokenData.expires_at > Date.now()) {
    return res.json({
      active: true,
      scope: tokenData.scope,
      client_id: tokenData.client_id,
      username: tokenData.user.username,
      token_type: 'Bearer',
      exp: Math.floor(tokenData.expires_at / 1000),
      iat: Math.floor((tokenData.expires_at - 3600000) / 1000),
      sub: tokenData.user.username,
      email: tokenData.user.email,
      name: tokenData.user.name
    });
  }

  // Check refresh tokens
  const refreshData = refreshTokens.get(token);
  if (refreshData) {
    return res.json({
      active: true,
      scope: refreshData.scope,
      client_id: refreshData.client_id,
      username: refreshData.user.username,
      token_type: 'refresh_token',
      sub: refreshData.user.username
    });
  }

  return res.json({ active: false });
});

