// UserInfo Endpoint
// ========================
app.get('/userinfo', authenticateToken, (req, res) => {
  const { user, scope } = req.tokenData;
  const scopes = scope.split(' ');
  const response = { sub: user.username };

  if (scopes.includes('profile')) {
    response.name = user.name;
    response.preferred_username = user.username;
    response.role = user.role;
  }

  if (scopes.includes('email')) {
    response.email = user.email;
    response.email_verified = true;
  }

  res.json(response);
});

// ========================
// SSO Logout Endpoint
// ========================
app.get('/logout', (req, res) => {
  const { post_logout_redirect_uri } = req.query;

  // Invalidate all tokens for this user's session
  if (req.session && req.session.user) {
    const username = req.session.user.username;

    // Remove all access tokens for this user
    for (const [token, data] of accessTokens) {
      if (data.user.username === username) {
        accessTokens.delete(token);
      }
    }

    // Remove all refresh tokens for this user
    for (const [token, data] of refreshTokens) {
      if (data.user.username === username) {
        refreshTokens.delete(token);
      }
    }
  }

  req.session.destroy((err) => {
    if (post_logout_redirect_uri) {
      return res.redirect(post_logout_redirect_uri);
    }
    res.send(renderLogoutPage());
  });
});

